import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function monitorAgentFleet(chainName, agentAddresses) {
  const results = await Promise.all(
    agentAddresses.map(addr =>
      client.BalanceService.getTokenBalancesForWalletAddress(chainName, addr)
    )
  );
  return agentAddresses.map((addr, i) => ({
    agent: addr,
    totalUSD: (results[i].data?.items ?? []).reduce((s, t) => s + (t.quote ?? 0), 0),
    tokenCount: results[i].data?.items?.length ?? 0,
  }));
}
